#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the elliptic curve parameters
#define P 23
#define A 1
#define B 1
#define G_X 5
#define G_Y 1

// Function to compute the shared secret
void compute_shared_secret(int private_key, int public_key_x, int public_key_y) {
 int shared_secret_x, shared_secret_y;
 // Compute the shared secret using the private key and public key
 shared_secret_x = (private_key * public_key_x) % P;
 shared_secret_y = (private_key * public_key_y) % P;
 printf("Shared secret: (%d, %d)\n", shared_secret_x, shared_secret_y);
}

int main() {
 // Define the private keys
 int alice_private_key = 6;
 int bob_private_key = 15;

 // Compute the public keys
 int alice_public_key_x = (alice_private_key * G_X) % P;
 int alice_public_key_y = (alice_private_key * G_Y) % P;
 int bob_public_key_x = (bob_private_key * G_X) % P;
 int bob_public_key_y = (bob_private_key * G_Y) % P;

 // Compute the shared secret
 compute_shared_secret(alice_private_key, bob_public_key_x, bob_public_key_y);
 compute_shared_secret(bob_private_key, alice_public_key_x, alice_public_key_y);

 return 0;
}
